/**
 * @param {number} n
 * @param {number[][]} edges
 * @return {number}
 */
function solve(n, edges) {
    // We can model this problem using Disjoint Set Union (DSU) structure,
    // but we need to track not just connectivity, but also the parity of path weights.
    // This is equivalent to maintaining a Bipartite coloring or 2-coloring
    // information relative to the connected component.

    // We use a DSU structure where each element `parent[i]` stores the parent of node `i`.
    // We also use an array `diff[i]` to store the parity of the path weight from node `i`
    // to its current representative (root) of the set.
    // diff[i] = 0 means path weight is even.
    // diff[i] = 1 means path weight is odd.

    const parent = Array(n).fill(0).map((_, i) => i);
    // diff[i] stores the parity of the path weight from i to parent[i]
    const diff = Array(n).fill(0);

    /**
     * Finds the root of element i and updates diff[i] along the path (Path Compression).
     * @param {number} i 
     * @returns {number} The root of the set containing i.
     */
    function find(i) {
        if (parent[i] === i) {
            return i;
        }

        const root = find(parent[i]);

        // Update diff[i]: 
        // new_diff[i] = old_diff[i] + old_diff[parent[i]] (mod 2)
        // where old_diff[parent[i]] is the parity from old parent[i] to root.
        diff[i] = (diff[i] + diff[parent[i]]) % 2;

        parent[i] = root;
        return root;
    }

    let edgeCount = 0;

    for (const edge of edges) {
        const [u, v, w] = edge;

        const rootU = find(u);
        const rootV = find(v);

        if (rootU !== rootV) {
            // Case 1: u and v are in different components.
            // We add the edge. This does not create a cycle, so the condition is met.

            // Union operation: Merge rootV's component into rootU's component.
            parent[rootV] = rootU;

            // We need to set diff[rootV] such that the path parity from rootV to rootU is correct.
            // We know:
            // 1. Path(u -> rootU) parity is diff[u]
            // 2. Path(v -> rootV) parity is diff[v]
            // 3. Edge(u, v) parity is w
            // We want Path(rootV -> rootU) parity (which is diff[rootV])
            // Path(rootV -> rootU) = Path(rootV -> v) + Edge(v, u) + Path(u -> rootU) (all parities)
            // Path(rootV -> v) parity is diff[v] (since the edge is v->rootV, this is the reverse parity, which is the same)
            // Path(v -> rootV) = diff[v] => Path(rootV -> v) = diff[v]
            // Path(rootV -> rootU) = diff[v] + w + diff[u] (mod 2)

            diff[rootV] = (diff[v] + w + diff[u]) % 2;
            edgeCount++;

        } else {
            // Case 2: u and v are already in the same component.
            // Adding this edge creates a cycle. We must check the cycle parity.

            // Cycle path: u -> ... -> rootU -> ... -> v -> u (via new edge)
            // Parity of path u -> v through the existing tree: 
            // P_uv = Path(u -> rootU) + Path(v -> rootU) (mod 2)
            // P_uv = diff[u] + diff[v] (mod 2)

            // Cycle parity = P_uv + w (mod 2)
            const cycleParity = (diff[u] + diff[v] + w) % 2;

            if (cycleParity === 0) {
                // The cycle has an even weight sum. We add the edge.
                edgeCount++;
                // In DSU terms, we don't change the structure, but we effectively add the edge.
                // This structure inherently handles the property: if an edge is added, 
                // the relative parities (diff values) remain consistent with the new edge.
                // Since the parity is even, the new edge maintains the 2-coloring property.
            } else {
                // The cycle has an odd weight sum. We must NOT add the edge.
            }
        }
    }

    return edgeCount;
}

