class Solution {
    // DSU implementation with path parity tracking
    private static class DSU {
        int[] parent;
        // diff[i]: parity of the path weight from node i to its current parent
        int[] diff; 
        int n;

        public DSU(int n) {
            this.n = n;
            parent = new int[n];
            diff = new int[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                diff[i] = 0; // Path to itself is 0 weight (even)
            }
        }

        /**
         * Finds the root of element i and updates diff[i] along the path (Path Compression).
         * Returns the root of the set containing i.
         */
        public int find(int i) {
            if (parent[i] == i) {
                return i;
            }

            int root = find(parent[i]);

            // Update diff[i]: 
            // New path parity from i to root = (Old path i to parent[i]) + (Path parent[i] to root) (mod 2)
            diff[i] = (diff[i] + diff[parent[i]]) % 2;

            parent[i] = root;
            return root;
        }

        /**
         * Unites the sets containing u and v, returning true if a merge happened.
         * This specialized union updates the relative parity information.
         * @return The required parity for diff[rootV] if rootV is merged into rootU.
         */
        public int union(int u, int v, int w) {
            int rootU = find(u);
            int rootV = find(v);

            if (rootU != rootV) {
                // Merge rootV into rootU
                parent[rootV] = rootU;

                // We need to set diff[rootV] such that the path parity from rootV to rootU is correct.
                // Path(rootV -> rootU) = Path(rootV -> v) + Edge(v, u) + Path(u -> rootU) (mod 2)
                // Path(rootV -> v) parity is diff[v] (since diff[v] is parity v -> rootV, and this is the same for reverse path)
                // Path(u -> rootU) parity is diff[u]

                // The target is diff[rootV] = Parity(rootV -> rootU)
                // Parity(rootV -> rootU) = Parity(rootV -> v) + w + Parity(u -> rootU)
                // Parity(rootV -> v) = diff[v] (since diff[v] is v -> rootV, same as rootV -> v)
                diff[rootV] = (diff[v] + w + diff[u]) % 2;

                return 0; // Indicates successful merge
            } else {
                // Same component. Check cycle parity.
                // Cycle parity = Path(u -> v through tree) + w (mod 2)
                // Path(u -> v) = Path(u -> rootU) + Path(v -> rootU) (mod 2)
                // Path(u -> v) = diff[u] + diff[v] (mod 2)
                int cycleParity = (diff[u] + diff[v] + w) % 2;
                return cycleParity; // 0 if even, 1 if odd
            }
        }
    }

    public static long solve(long n_long, long[][] edges) {
        int n = (int) n_long;
        DSU dsu = new DSU(n);
        int edgeCount = 0;

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int w = (int) edge[2];

            int rootU = dsu.find(u);
            int rootV = dsu.find(v);

            if (rootU != rootV) {
                // Case 1: Different components. Always add.

                // Union operation: Merge rootV's component into rootU's component.
                dsu.parent[rootV] = rootU;

                // Calculate diff[rootV] = Parity(rootV -> rootU)
                // Path(rootV -> rootU) = Path(rootV -> v) + Edge(v, u) + Path(u -> rootU) (mod 2)
                // Path(rootV -> v) = diff[v]
                // Path(u -> rootU) = diff[u]
                dsu.diff[rootV] = (dsu.diff[v] + w + dsu.diff[u]) % 2;

                edgeCount++;

            } else {
                // Case 2: Same component. Check cycle parity.

                // Cycle parity = Path(u -> v through tree) + w (mod 2)
                // Path(u -> v) = diff[u] + diff[v] (mod 2)
                int cycleParity = (dsu.diff[u] + dsu.diff[v] + w) % 2;

                if (cycleParity == 0) {
                    // Even cycle sum. Add the edge.
                    edgeCount++;
                } 
                // If cycleParity == 1 (odd), do not add.
            }
        }

        return edgeCount;
    }
}
